namespace UniversityCourseCatalog.Models;

public class Department
{
    public int Id { get; set; }
    public string Name { get; set; } = string.Empty;
    public string Code { get; set; } = string.Empty;
    public string Description { get; set; } = string.Empty;
}

namespace UniversityCourseCatalog.Models;

public class Course
{
    public int Id { get; set; }
    public string Title { get; set; } = string.Empty;
    public string Code { get; set; } = string.Empty;
    public string Description { get; set; } = string.Empty;
    public int Credits { get; set; }
    public string Schedule { get; set; } = string.Empty;
    public string InstructorName { get; set; } = string.Empty;
    public string InstructorBio { get; set; } = string.Empty;
    public int DepartmentId { get; set; }
    public string DepartmentName { get; set; } = string.Empty;
    public bool IsFeatured { get; set; }
}

using System.ComponentModel.DataAnnotations;

namespace UniversityCourseCatalog.Models;

public class EnrollmentRequest
{
    [Required(ErrorMessage = "Full name is required.")]
    [StringLength(100)]
    public string FullName { get; set; } = string.Empty;

    [Required(ErrorMessage = "Student ID is required.")]
    [RegularExpression(@"^[A-Z0-9]{6,10}$", ErrorMessage = "Student ID must be 6-10 uppercase alphanumeric characters.")]
    public string StudentId { get; set; } = string.Empty;

    [Required(ErrorMessage = "Please select a course.")]
    [Range(1, int.MaxValue, ErrorMessage = "Please select a course.")]
    public int CourseId { get; set; }
}

using UniversityCourseCatalog.Models;

namespace UniversityCourseCatalog.Services;

public class CatalogService
{
    private readonly List<Department> _departments;
    private readonly List<Course> _courses;

    public CatalogService()
    {
        _departments = new List<Department>
        {
            new() { Id = 1, Name = "Computer Science", Code = "CS", Description = "Study of computation, algorithms, and information systems." },
            new() { Id = 2, Name = "Mathematics", Code = "MATH", Description = "Study of numbers, structures, and patterns." },
            new() { Id = 3, Name = "Physics", Code = "PHYS", Description = "Study of matter, energy, and the fundamental forces of nature." },
            new() { Id = 4, Name = "English", Code = "ENG", Description = "Study of literature, writing, and language." },
            new() { Id = 5, Name = "History", Code = "HIST", Description = "Study of past events and civilizations." },
        };

        _courses = new List<Course>
        {
            new() { Id = 1, Title = "Introduction to Programming", Code = "CS 101", Description = "Learn the fundamentals of programming using Python. Topics include variables, control flow, functions, and basic data structures.", Credits = 3, Schedule = "Mon/Wed/Fri 9:00–9:50 AM", InstructorName = "Dr. Sarah Chen", InstructorBio = "Dr. Chen has 15 years of experience in software engineering and has published extensively on programming pedagogy.", DepartmentId = 1, DepartmentName = "Computer Science", IsFeatured = true },
            new() { Id = 2, Title = "Data Structures & Algorithms", Code = "CS 201", Description = "Study of fundamental data structures (trees, graphs, hash tables) and algorithm design techniques including divide-and-conquer and dynamic programming.", Credits = 4, Schedule = "Tue/Thu 10:30–11:45 AM", InstructorName = "Dr. James Liu", InstructorBio = "Dr. Liu specializes in algorithm optimization and competitive programming. He has coached multiple ICPC finalist teams.", DepartmentId = 1, DepartmentName = "Computer Science", IsFeatured = true },
            new() { Id = 3, Title = "Database Systems", Code = "CS 305", Description = "Design and implementation of relational databases, SQL, normalization, indexing, and transaction management.", Credits = 3, Schedule = "Mon/Wed 2:00–3:15 PM", InstructorName = "Dr. Maria Garcia", InstructorBio = "Dr. Garcia worked at Oracle for a decade before joining academia. Her research focuses on distributed database systems.", DepartmentId = 1, DepartmentName = "Computer Science", IsFeatured = false },
            new() { Id = 4, Title = "Calculus I", Code = "MATH 151", Description = "Limits, derivatives, and integrals of single-variable functions with applications to science and engineering.", Credits = 4, Schedule = "Mon/Wed/Fri 10:00–10:50 AM", InstructorName = "Dr. Robert Taylor", InstructorBio = "Dr. Taylor is an award-winning educator who has taught calculus for over 20 years.", DepartmentId = 2, DepartmentName = "Mathematics", IsFeatured = true },
            new() { Id = 5, Title = "Linear Algebra", Code = "MATH 220", Description = "Vectors, matrices, linear transformations, eigenvalues, and applications to systems of equations.", Credits = 3, Schedule = "Tue/Thu 1:00–2:15 PM", InstructorName = "Dr. Emily Park", InstructorBio = "Dr. Park researches applications of linear algebra in machine learning and data science.", DepartmentId = 2, DepartmentName = "Mathematics", IsFeatured = false },
            new() { Id = 6, Title = "General Physics I", Code = "PHYS 101", Description = "Mechanics, thermodynamics, and waves. Includes laboratory component.", Credits = 4, Schedule = "Mon/Wed/Fri 11:00–11:50 AM, Lab: Thu 2:00–4:50 PM", InstructorName = "Dr. Alan Foster", InstructorBio = "Dr. Foster's research includes experimental particle physics. He is passionate about making physics accessible to all students.", DepartmentId = 3, DepartmentName = "Physics", IsFeatured = true },
            new() { Id = 7, Title = "Quantum Mechanics", Code = "PHYS 310", Description = "Wave functions, Schrödinger equation, quantum states, and applications to atomic systems.", Credits = 3, Schedule = "Tue/Thu 9:00–10:15 AM", InstructorName = "Dr. Priya Sharma", InstructorBio = "Dr. Sharma is a theoretical physicist whose work on quantum computing has been featured in Nature.", DepartmentId = 3, DepartmentName = "Physics", IsFeatured = false },
            new() { Id = 8, Title = "English Composition", Code = "ENG 101", Description = "Develop college-level writing skills through essays, research papers, and peer review workshops.", Credits = 3, Schedule = "Mon/Wed 9:00–10:15 AM", InstructorName = "Prof. Diana Wells", InstructorBio = "Prof. Wells is a published novelist and essayist who brings creative energy to academic writing instruction.", DepartmentId = 4, DepartmentName = "English", IsFeatured = false },
            new() { Id = 9, Title = "American Literature", Code = "ENG 250", Description = "Survey of American literature from the colonial period to the present, examining major authors and literary movements.", Credits = 3, Schedule = "Tue/Thu 11:00 AM–12:15 PM", InstructorName = "Dr. Marcus Johnson", InstructorBio = "Dr. Johnson specializes in 20th-century American fiction and has authored three books on the Harlem Renaissance.", DepartmentId = 4, DepartmentName = "English", IsFeatured = false },
            new() { Id = 10, Title = "World History to 1500", Code = "HIST 101", Description = "Survey of world civilizations from antiquity through the medieval period, covering political, social, and cultural developments.", Credits = 3, Schedule = "Mon/Wed/Fri 1:00–1:50 PM", InstructorName = "Dr. Karen Mitchell", InstructorBio = "Dr. Mitchell is an archaeologist and historian whose fieldwork spans three continents.", DepartmentId = 5, DepartmentName = "History", IsFeatured = false },
        };
    }

    public List<Department> GetDepartments() => _departments;

    public Department? GetDepartment(int id) => _departments.FirstOrDefault(d => d.Id == id);

    public List<Course> GetCourses(string? searchTerm = null, int? departmentId = null)
    {
        var query = _courses.AsEnumerable();

        if (departmentId.HasValue)
            query = query.Where(c => c.DepartmentId == departmentId.Value);

        if (!string.IsNullOrWhiteSpace(searchTerm))
        {
            var term = searchTerm.Trim().ToLowerInvariant();
            query = query.Where(c =>
                c.Title.Contains(term, StringComparison.OrdinalIgnoreCase) ||
                c.Code.Contains(term, StringComparison.OrdinalIgnoreCase) ||
                c.InstructorName.Contains(term, StringComparison.OrdinalIgnoreCase));
        }

        return query.ToList();
    }

    public List<Course> GetFeaturedCourses() => _courses.Where(c => c.IsFeatured).ToList();

    public Course? GetCourse(int id) => _courses.FirstOrDefault(c => c.Id == id);

    public List<Course> GetAllCourses() => _courses;
}

