@page "/enroll"
@using UniversityCourseCatalog.Models
@using UniversityCourseCatalog.Services
@inject CatalogService CatalogService
@rendermode InteractiveServer

<PageTitle>Enrollment Request</PageTitle>

<h1>Enrollment Request</h1>
<p>Fill out the form below to submit an enrollment request.</p>

@if (_submitted)
{
    <div class="alert alert-success">
        <h4>Request Submitted!</h4>
        <p>Thank you, <strong>@_model.FullName</strong>. Your enrollment request for
        <strong>@_selectedCourseTitle</strong> has been received. You will be notified by email once processed.</p>
        <a href="enroll" class="btn btn-outline-primary mt-2">Submit Another Request</a>
    </div>
}
else
{
    <EditForm Model="_model" OnValidSubmit="HandleSubmit" FormName="enrollment" class="mt-3">
        <DataAnnotationsValidator />
        <ValidationSummary class="text-danger" />

        <div class="mb-3">
            <label for="fullName" class="form-label">Full Name</label>
            <InputText id="fullName" class="form-control" @bind-Value="_model.FullName" />
            <ValidationMessage For="() => _model.FullName" class="text-danger" />
        </div>

        <div class="mb-3">
            <label for="studentId" class="form-label">Student ID</label>
            <InputText id="studentId" class="form-control" @bind-Value="_model.StudentId" />
            <ValidationMessage For="() => _model.StudentId" class="text-danger" />
            <div class="form-text">6-10 uppercase alphanumeric characters (e.g., ABC12345)</div>
        </div>

        <div class="mb-3">
            <label for="courseId" class="form-label">Course</label>
            <InputSelect id="courseId" class="form-select" @bind-Value="_model.CourseId">
                <option value="0">-- Select a course --</option>
                @foreach (var course in _allCourses)
                {
                    <option value="@course.Id">@course.Code - @course.Title</option>
                }
            </InputSelect>
            <ValidationMessage For="() => _model.CourseId" class="text-danger" />
        </div>

        <button type="submit" class="btn btn-primary">Submit Enrollment Request</button>
    </EditForm>
}

@code {
    [SupplyParameterFromQuery]
    public int? CourseId { get; set; }

    private EnrollmentRequest _model = new();
    private List<Course> _allCourses = new();
    private bool _submitted;
    private string _selectedCourseTitle = string.Empty;

    protected override void OnInitialized()
    {
        _allCourses = CatalogService.GetAllCourses();
        if (CourseId.HasValue)
            _model.CourseId = CourseId.Value;
    }

    private void HandleSubmit()
    {
        var course = CatalogService.GetCourse(_model.CourseId);
        _selectedCourseTitle = course is not null ? $"{course.Code} - {course.Title}" : "Unknown";
        _submitted = true;
    }
}

