@page "/courses"
@using UniversityCourseCatalog.Models
@using UniversityCourseCatalog.Services
@inject CatalogService CatalogService
@inject NavigationManager Navigation

<PageTitle>Browse Courses</PageTitle>

<h1>Browse Courses</h1>

<div class="row mb-3">
    <div class="col-md-6">
        <input type="text" class="form-control" placeholder="Search by title, code, or instructor..."
               @bind="SearchTerm" @bind:event="oninput" @bind:after="ApplyFilters" />
    </div>
    <div class="col-md-4">
        <select class="form-select" @bind="SelectedDepartmentId" @bind:after="ApplyFilters">
            <option value="0">All Departments</option>
            @foreach (var dept in _departments)
            {
                <option value="@dept.Id">@dept.Name</option>
            }
        </select>
    </div>
</div>

@if (!_courses.Any())
{
    <div class="alert alert-info">No courses match your search criteria.</div>
}
else
{
    <table class="table table-striped table-hover">
        <thead>
            <tr>
                <th>Code</th>
                <th>Title</th>
                <th>Department</th>
                <th>Credits</th>
                <th>Instructor</th>
                <th></th>
            </tr>
        </thead>
        <tbody>
            @foreach (var course in _courses)
            {
                <tr>
                    <td>@course.Code</td>
                    <td>@course.Title</td>
                    <td>@course.DepartmentName</td>
                    <td>@course.Credits</td>
                    <td>@course.InstructorName</td>
                    <td><a href="courses/@course.Id" class="btn btn-outline-primary btn-sm">Details</a></td>
                </tr>
            }
        </tbody>
    </table>
}

@code {
    [SupplyParameterFromQuery]
    public int? DepartmentId { get; set; }

    private string SearchTerm { get; set; } = string.Empty;
    private int SelectedDepartmentId { get; set; }
    private List<Course> _courses = new();
    private List<Department> _departments = new();

    protected override void OnInitialized()
    {
        _departments = CatalogService.GetDepartments();
        if (DepartmentId.HasValue)
            SelectedDepartmentId = DepartmentId.Value;
        ApplyFilters();
    }

    private void ApplyFilters()
    {
        int? deptFilter = SelectedDepartmentId > 0 ? SelectedDepartmentId : null;
        _courses = CatalogService.GetCourses(SearchTerm, deptFilter);
    }
}

